    public void handleEvent1(String data) {
        if (data != null && !data.isEmpty()) {
            log.info("Processing event 1: " + data);
            this.lastUpdateTime = System.currentTimeMillis();
            if (data.length() > 10) {
                log.fine("Large data received in event 1");
            }
        }
    }

