    public void complexLogic1(int x, int y) {
        if (x > 0) {
            if (y > 0) {
                for (int j=0; j<x; j++) {
                    if (j % 2 == 0) { log.info("Even"); } else { log.info("Odd"); }
                }
            } else {
                while (x > 0) { x--; }
            }
        } else {
            switch(y) {
                case 1: log.info("1"); break;
                case 2: log.info("2"); break;
                case 3: log.info("3"); break;
                default: log.info("def"); break;
            }
        }
    }

